BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?req ?reqName ?verify ?verifyName WHERE {
  ?verify rdf:type vocab:verify .
  ?verify vocab:Dependency_client ?req .
  ?req rdf:type vocab:tmt%20requirement .
  OPTIONAL { ?req vocab:NamedElement_name ?reqName }
  OPTIONAL { ?verify vocab:NamedElement_name ?verifyName }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?elem ?name ?type WHERE {
  ?elem rdf:type ?type .
  OPTIONAL { ?elem vocab:NamedElement_name ?name . }
  FILTER(BOUND(?name) && CONTAINS(LCASE(STR(?name)), "verify"))
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?req ?reqName ?dep ?depType ?depName WHERE {
  # Find verification-ish dependencies where the dependency client or supplier is in/around the test case element
  ?tc vocab:NamedElement_name ?tcName .
  FILTER(CONTAINS(LCASE(STR(?tcName)), LCASE("Test%20Activity%20to%20Verify")))
  .

  ?dep rdf:type ?depType .

  # dependency endpoints
  { ?dep vocab:Dependency_client ?tc }
  UNION
  { ?dep vocab:Dependency_supplier ?tc }

  ?dep vocab:Dependency_client|vocab:Dependency_supplier ?req .
  ?req rdf:type vocab:tmt%20requirement .

  OPTIONAL { ?req vocab:NamedElement_name ?reqName . }
  OPTIONAL { ?dep vocab:NamedElement_name ?depName . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?dep ?depName ?req ?reqName ?sourceElem ?sourceName WHERE {
  # Start from any element with 'verify' in its name
  ?sourceElem vocab:NamedElement_name ?sourceName .
  FILTER(CONTAINS(LCASE(STR(?sourceName)), LCASE("verify"))).

  # Find dependencies that are connected in any direction to that element
  ?dep rdf:type ?depType .
  FILTER(BOUND(?depType)).
  { ?dep vocab:Dependency_client ?sourceElem . }
  UNION
  { ?dep vocab:Dependency_supplier ?sourceElem . }

  # And those dependencies reference tmt requirements
  { ?dep vocab:Dependency_client ?req . }
  UNION
  { ?dep vocab:Dependency_supplier ?req . }

  ?req rdf:type vocab:tmt%20requirement .
  OPTIONAL { ?dep vocab:NamedElement_name ?depName . }
  OPTIONAL { ?req vocab:NamedElement_name ?reqName . }
}
LIMIT 25
